function scheduleVizLoad(){if(!document.querySelector("[data-viz]"))return;if(window.matchMedia("(prefers-reduced-motion: reduce)").matches)return;const e=()=>{if(document.querySelector("script[data-sonu-viz]"))return;const e=document.querySelector('link[href*="site.min.css"]');if(!e||!e.href)return;const t=e.href.replace(/\/css\/site\.min\.css(\?.*)?$/i,"/js/viz.min.js$1"),n=document.createElement("script");n.src=t,n.async=!0,n.setAttribute("data-sonu-viz",""),document.body.appendChild(n)};"requestIdleCallback"in window?requestIdleCallback(e,{timeout:600}):setTimeout(e,16)}function normalizePathname(e){return e.replace(/\\/g,"/").replace(/\/index(?:\.html)?$/i,"/").replace(/\.html$/i,"").replace(/\/+$/,"")||"/"}function getSection(e){return normalizePathname(e).split("/").filter(Boolean)[0]||"index"}function setActiveNavLink(){const e=normalizePathname(window.location.pathname),t=getSection(e);document.querySelectorAll(".site-nav a:not(.nav-name)").forEach(n=>{const r=n.getAttribute("href");if(!r)return;const i=normalizePathname(new URL(r,window.location.href).pathname),o=getSection(i),a="index"===o;(i===e||!a&&o===t||a&&"/"===e)&&n.setAttribute("aria-current","page")})}function initExternalLinks(){document.querySelectorAll('a[target="_blank"]').forEach(e=>{e.getAttribute("rel")||e.setAttribute("rel","noopener noreferrer")})}function initThemeToggle(){const e=document.querySelector(".theme-toggle");if(!e)return;const t=localStorage.getItem("theme"),n=window.matchMedia("(prefers-color-scheme: dark)").matches,r=t||(n?"dark":"light");document.documentElement.setAttribute("data-theme",r),updateToggleLabel(e,r),e.addEventListener("click",()=>{const t="dark"===document.documentElement.getAttribute("data-theme")?"light":"dark";document.documentElement.setAttribute("data-theme",t),localStorage.setItem("theme",t),updateToggleLabel(e,t)})}function updateToggleLabel(e,t){if(!e)return;const n=e.querySelector(".icon-sun"),r=e.querySelector(".icon-moon");if(n){const e="dark"===t;n.style.display=e?"block":"none",n.setAttribute("aria-hidden",e?"false":"true")}if(r){const e="dark"!==t;r.style.display=e?"block":"none",r.setAttribute("aria-hidden",e?"false":"true")}e.setAttribute("aria-label","dark"===t?"Switch to light mode":"Switch to dark mode")}document.addEventListener("DOMContentLoaded",()=>{setActiveNavLink(),initExternalLinks(),initThemeToggle(),scheduleVizLoad()});